// Zbierz wszystko z RSS i BIP, filtruj po Kraśniku, ostatnie 7 dni
const allItems = [];
const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);

for (const item of $input.all()) {
  const d = item.json;

  // RSS items
  if (d.title && d.link) {
    const pubDate = new Date(d.pubDate || d.isoDate || 0);
    if (pubDate >= weekAgo) {
      allItems.push({
        zrodlo: d.creator || 'Media',
        tytul: d.title,
        link: d.link,
        data: pubDate.toISOString(),
        opis: (d.contentSnippet || d.content || '').substring(0, 200),
        typ: 'news'
      });
    }
  }

  // BIP
  if (d.tytuly && Array.isArray(d.tytuly)) {
    for (const t of d.tytuly.slice(0, 8)) {
      allItems.push({
        zrodlo: 'BIP Powiat',
        tytul: t,
        link: 'https://powiatkrasnik.e-bip.eu/',
        data: new Date().toISOString(),
        opis: '',
        typ: 'bip'
      });
    }
  }
}

// Filtruj po Kraśniku
const kw = ['kraśnik','krasnik','kraśnick','krasnick','powiat','starosta','starostwo','rada powiatu','annopol','urzędów','gościeradów','dzierzkowice','szastarka','trzydnik','wilkołaz','zakrzówek'];

const filtered = allItems.filter(i => {
  if (i.typ === 'bip') return true;
  const txt = `${i.tytul} ${i.opis}`.toLowerCase();
  return kw.some(k => txt.includes(k));
});

const sorted = filtered.sort((a, b) => new Date(b.data) - new Date(a.data)).slice(0, 30);

const news = sorted.filter(i => i.typ === 'news');
const bip = sorted.filter(i => i.typ === 'bip');

const now = new Date();
const weekStart = new Date(now - 7 * 24 * 60 * 60 * 1000);

return [{
  json: {
    news,
    bip,
    total: sorted.length,
    news_count: news.length,
    bip_count: bip.length,
    week_start: weekStart.toLocaleDateString('pl-PL'),
    week_end: now.toLocaleDateString('pl-PL'),
    issue_number: Math.ceil((now - new Date('2026-01-01')) / (7 * 24 * 60 * 60 * 1000))
  }
}];

