// Przygotuj listę emaili + dane newslettera
const subscribers = $input.all().map(i => i.json);
const newsletter = $('Generuj HTML Newsletter').first().json;

const validEmails = subscribers.filter(s => 
  s.email && 
  s.email.includes('@') && 
  (s.status || 'active') === 'active'
);

return validEmails.map(s => ({
  json: {
    email: s.email,
    imie: s.imie || 'Mieszkańcu',
    html: newsletter.html.replace('Mieszkańcu', s.imie || 'Mieszkańcu'),
    subject: newsletter.subject,
    plain_text: newsletter.plain_text
  }
}));

